import Foundation
import Darwin

public actor UsagesFileManager {
    // Internal init so tests can create isolated instances via @testable import.
    // Production code must use `UsagesFileManager.shared`.
    public static let shared = UsagesFileManager()

    nonisolated public let filePath: String
    nonisolated public let lockPath: String
    private let logger: FileLogger
    private let lockTimeoutSeconds: TimeInterval

    init(
        filePath: String? = nil,
        logger: FileLogger = Loggers.app,
        lockTimeoutSeconds: TimeInterval = 5.0
    ) {
        let home = FileManager.default.homeDirectoryForCurrentUser.path
        self.filePath = filePath ?? "\(home)/.cache/ai-usages-tracker/usages.json"
        self.logger = logger
        self.lockPath = self.filePath + ".lock"
        self.lockTimeoutSeconds = lockTimeoutSeconds

        let dir = (self.filePath as NSString).deletingLastPathComponent
        do {
            try FileManager.default.createDirectory(atPath: dir, withIntermediateDirectories: true, attributes: nil)
        } catch {
            logger.log(.error, "Failed to create directory \(dir): \(error)")
        }
    }

    // MARK: - Public

    public func read() async -> UsagesFile {
        do {
            return try await withFileLock(mode: LOCK_SH) { readUnsafe() }
        } catch is CancellationError {
            return UsagesFile()
        } catch {
            logger.log(.warning, "flock read failed — returning empty file: \(error)")
            return UsagesFile()
        }
    }

    public func update(with entries: [VendorUsageEntry]) async {
        await update(with: entries, outagesByVendor: [:])
    }

    /// Applies a usage merge plus per-vendor outage replacement in a single locked read-modify-write.
    ///
    /// Outage policy per vendor key in `outagesByVendor`:
    /// - present, non-empty list → replaces all outages of that vendor
    /// - present, empty list → removes all outages of that vendor ("all clear")
    /// - absent → outages of that vendor are preserved as-is (fetch failed, or no connector for it)
    public func update(
        with entries: [VendorUsageEntry],
        outagesByVendor: [Vendor: [Outage]]
    ) async {
        do {
            try await withFileLock(mode: LOCK_EX) {
                var file = readUnsafe()
                file = merge(existing: file, incoming: entries)
                if !outagesByVendor.isEmpty {
                    file.outages = applyOutageReplacement(
                        existing: file.outages,
                        replacements: outagesByVendor
                    )
                }
                writeUnsafe(file)
            }
        } catch is CancellationError {
            return
        } catch {
            logger.log(.warning, "flock update failed — skipping write: \(error)")
        }
    }

    // MARK: - Active-account update

    public func updateIsActive(vendor: Vendor, activeAccount: AccountEmail?) async {
        do {
            try await withFileLock(mode: LOCK_EX) {
                var file = readUnsafe()
                var changed = false
                for i in file.usages.indices where file.usages[i].vendor == vendor {
                    let newActive = file.usages[i].account == activeAccount
                    if file.usages[i].isActive != newActive {
                        file.usages[i].isActive = newActive
                        changed = true
                    }
                }
                if changed {
                    writeUnsafe(file)
                }
            }
        } catch is CancellationError {
            return
        } catch {
            logger.log(.warning, "flock updateIsActive failed — skipping: \(error)")
        }
    }

    // MARK: - Outage replacement

    /// Replaces outages per-vendor while preserving outages for vendors absent from `replacements`.
    /// Vendors not covered by a status connector (or producers external to this app) keep their
    /// entries untouched, so the file format stays open to multiple producers.
    func applyOutageReplacement(
        existing: [Outage],
        replacements: [Vendor: [Outage]]
    ) -> [Outage] {
        var result = existing.filter { replacements[$0.vendor] == nil }
        for (_, newOutages) in replacements {
            result.append(contentsOf: newOutages)
        }
        return result
    }

    // MARK: - Merge logic

    func merge(existing: UsagesFile, incoming: [VendorUsageEntry]) -> UsagesFile {
        // Usage entries are vendor-keyed upserts; outages are handled separately by
        // `applyOutageReplacement`, which the public `update(with:outagesByVendor:)` runs
        // after this merge. The file format is open to external outage producers for
        // vendors without a status connector.
        var usages = existing.usages
        var indexByKey: [String: Int] = [:]
        for (i, entry) in usages.enumerated() {
            indexByKey["\(entry.vendor.rawValue)|\(entry.account.rawValue)"] = i
        }
        for entry in incoming {
            let key = "\(entry.vendor.rawValue)|\(entry.account.rawValue)"
            if let idx = indexByKey[key] {
                if entry.lastError != nil {
                    // Errors must not erase previously acquired data: the file may hold good
                    // metrics from a prior successful fetch while the connector's in-memory
                    // lastKnownMetrics is empty (e.g. after an app restart).
                    var merged = entry
                    if merged.metrics.isEmpty {
                        merged.metrics = usages[idx].metrics
                    }
                    if merged.lastAcquiredOn == nil {
                        merged.lastAcquiredOn = usages[idx].lastAcquiredOn
                    }
                    usages[idx] = merged
                } else {
                    usages[idx] = entry
                }
            } else {
                indexByKey[key] = usages.count
                usages.append(entry)
            }
        }

        return UsagesFile(usages: usages, outages: existing.outages)
    }

    // MARK: - Lock-guarded internals

    /// Acquires an advisory flock on the dedicated lock file, runs `body`, then releases.
    /// Uses a separate lock file because atomic writes replace the JSON inode, making
    /// flock on the data file itself ineffective for protecting external readers.
    private func withFileLock<T>(mode: Int32, body: () throws -> T) async throws -> T {
        let fd = Darwin.open(lockPath, O_CREAT | O_RDWR, 0o644)
        guard fd >= 0 else { throw FileManagerError.cannotOpenLockFile(path: lockPath) }
        defer { Darwin.close(fd) }

        let deadline = Date().addingTimeInterval(lockTimeoutSeconds)
        while flock(fd, mode | LOCK_NB) != 0 {
            guard Date() < deadline else {
                throw FileManagerError.lockTimeout(path: lockPath, timeoutSeconds: lockTimeoutSeconds)
            }
            try await Task.sleep(for: .milliseconds(50))
        }
        defer { flock(fd, LOCK_UN) }

        return try body()
    }

    // MARK: - Unsafe (actor-isolated, no external lock needed)

    private func readUnsafe() -> UsagesFile {
        guard let data = FileManager.default.contents(atPath: filePath) else {
            return UsagesFile()
        }
        do {
            return try JSONDecoder().decode(UsagesFile.self, from: data)
        } catch {
            logger.log(.error, "Failed to decode \(filePath): \(error)")
            return UsagesFile()
        }
    }

    private func writeUnsafe(_ file: UsagesFile) {
        let encoder = JSONEncoder()
        encoder.outputFormatting = [.prettyPrinted, .sortedKeys]
        guard let data = try? encoder.encode(file) else {
            logger.log(.error, "Failed to encode usages file")
            return
        }
        do {
            try data.write(to: URL(fileURLWithPath: filePath), options: .atomic)
        } catch {
            logger.log(.error, "Atomic write failed: \(error)")
            return
        }
        logger.log(.debug, "Wrote usages file to \(filePath)")
    }
}

enum FileManagerError: Error, CustomStringConvertible {
    case cannotOpenLockFile(path: String)
    case lockTimeout(path: String, timeoutSeconds: Double)

    var description: String {
        switch self {
        case let .cannotOpenLockFile(path):
            "Cannot open lock file at \(path)"
        case let .lockTimeout(path, secs):
            "Could not acquire flock on \(path) within \(secs)s"
        }
    }
}

import Foundation

// MARK: - Root

/// The top-level file model: `{ usages: [...], outages?: [...] }`.
///
/// `outages` is an optional sibling written by an upstream status-fetching process.
/// When no incident is ongoing the upstream writer is expected to drop the key
/// entirely; the encoder here honours that convention by emitting nothing when
/// the in-memory array is empty.
public struct UsagesFile: Codable, Equatable, Sendable {
    public var usages: [VendorUsageEntry]
    public var outages: [Outage]

    public init(usages: [VendorUsageEntry] = [], outages: [Outage] = []) {
        self.usages = usages
        self.outages = outages
    }

    /// Grouped view for the UI — vendors without outages are omitted.
    public var outagesByVendor: [Vendor: [Outage]] {
        Dictionary(grouping: outages, by: \.vendor)
    }

    private enum CodingKeys: String, CodingKey {
        case usages, outages
    }

    public init(from decoder: Decoder) throws {
        let container = try decoder.container(keyedBy: CodingKeys.self)
        usages = try container.decodeIfPresent([VendorUsageEntry].self, forKey: .usages) ?? []
        outages = try container.decodeIfPresent([Outage].self, forKey: .outages) ?? []
    }

    public func encode(to encoder: Encoder) throws {
        var container = encoder.container(keyedBy: CodingKeys.self)
        try container.encode(usages, forKey: .usages)
        // Upstream convention: absent key when no ongoing outage — mirror that on write
        // so the file never carries a stale empty array between incidents.
        if !outages.isEmpty {
            try container.encode(outages, forKey: .outages)
        }
    }
}

// MARK: - VendorUsageEntry

public struct VendorUsageEntry: Codable, Equatable, Sendable, Identifiable {
    public var id: String { "\(vendor.rawValue):\(account.rawValue)" }

    public let vendor: Vendor
    public let account: AccountEmail
    public var isActive: Bool
    public var lastAcquiredOn: ISODate?
    public var lastError: UsageError?
    public var metrics: [UsageMetric]

    public init(
        vendor: Vendor,
        account: AccountEmail,
        isActive: Bool = false,
        lastAcquiredOn: ISODate? = nil,
        lastError: UsageError? = nil,
        metrics: [UsageMetric] = []
    ) {
        self.vendor = vendor
        self.account = account
        self.isActive = isActive
        self.lastAcquiredOn = lastAcquiredOn
        self.lastError = lastError
        self.metrics = metrics
    }
}

// MARK: - Error

public struct UsageError: Codable, Equatable, Sendable {
    public let timestamp: ISODate
    public let type: String

    public init(timestamp: ISODate, type: String) {
        self.timestamp = timestamp
        self.type = type
    }
}

// MARK: - Outage

/// An active incident on a vendor's platform, written by an upstream status-fetching process.
/// The upstream writer removes entries as incidents resolve, so a missing or empty
/// `outages` array means "all clear".
public struct Outage: Codable, Equatable, Sendable, Identifiable {
    public let vendor: Vendor
    public let errorMessage: String
    public let severity: OutageSeverity
    public let since: ISODate
    public let href: URL?

    /// Composite id — outages have no stable upstream id in this shape, so we
    /// derive one from the fields that together identify a single incident row.
    public var id: String {
        "\(vendor.rawValue)|\(since.rawValue)|\(href?.absoluteString ?? "")"
    }

    public init(
        vendor: Vendor,
        errorMessage: String,
        severity: OutageSeverity,
        since: ISODate,
        href: URL? = nil
    ) {
        self.vendor = vendor
        self.errorMessage = errorMessage
        self.severity = severity
        self.since = since
        self.href = href
    }

    private enum CodingKeys: String, CodingKey {
        case vendor, errorMessage, severity, since, href
    }

    public init(from decoder: Decoder) throws {
        let container = try decoder.container(keyedBy: CodingKeys.self)
        vendor = try container.decode(Vendor.self, forKey: .vendor)
        errorMessage = try container.decode(String.self, forKey: .errorMessage)
        severity = try container.decode(OutageSeverity.self, forKey: .severity)
        since = try container.decode(ISODate.self, forKey: .since)
        if let hrefString = try container.decodeIfPresent(String.self, forKey: .href) {
            guard let parsed = URL(string: hrefString) else {
                throw DecodingError.dataCorruptedError(
                    forKey: .href, in: container,
                    debugDescription: "Invalid URL string: \(hrefString)")
            }
            href = parsed
        } else {
            href = nil
        }
    }
}

// MARK: - Metric (polymorphic on "type" discriminator)

public enum UsageMetric: Codable, Equatable, Sendable {
    case timeWindow(name: String, resetAt: ISODate?, windowDuration: DurationMinutes, usagePercent: UsagePercent)
    case payAsYouGo(name: String, currentAmount: Double, currency: String)
    /// A metric type not yet known to this client; retained for round-trip fidelity.
    case unknown(String)

    // MARK: Kind

    public var kind: MetricKind {
        switch self {
        case .timeWindow:       .timeWindow
        case .payAsYouGo:       .payAsYouGo
        case .unknown(let t):   .unknown(t)
        }
    }

    // MARK: Coding

    private enum CodingKeys: String, CodingKey {
        case type, name, resetAt
        case windowDuration = "windowDurationMinutes"
        case usagePercent, currentAmount, currency
    }

    public init(from decoder: Decoder) throws {
        let container = try decoder.container(keyedBy: CodingKeys.self)
        let metricKind = try container.decode(MetricKind.self, forKey: .type)
        switch metricKind {
        case .timeWindow:
            self = .timeWindow(
                name: try container.decode(String.self, forKey: .name),
                resetAt: try container.decodeIfPresent(ISODate.self, forKey: .resetAt),
                windowDuration: try container.decode(DurationMinutes.self, forKey: .windowDuration),
                usagePercent: try container.decode(UsagePercent.self, forKey: .usagePercent)
            )
        case .payAsYouGo:
            self = .payAsYouGo(
                name: try container.decode(String.self, forKey: .name),
                currentAmount: try container.decode(Double.self, forKey: .currentAmount),
                currency: try container.decode(String.self, forKey: .currency)
            )
        case .unknown(let t):
            self = .unknown(t)
        }
    }

    public func encode(to encoder: Encoder) throws {
        var container = encoder.container(keyedBy: CodingKeys.self)
        switch self {
        case let .timeWindow(name, resetAt, windowDuration, usagePercent):
            try container.encode(MetricKind.timeWindow, forKey: .type)
            try container.encode(name, forKey: .name)
            try container.encodeIfPresent(resetAt, forKey: .resetAt)
            try container.encode(windowDuration, forKey: .windowDuration)
            try container.encode(usagePercent, forKey: .usagePercent)
        case let .payAsYouGo(name, currentAmount, currency):
            try container.encode(MetricKind.payAsYouGo, forKey: .type)
            try container.encode(name, forKey: .name)
            try container.encode(currentAmount, forKey: .currentAmount)
            try container.encode(currency, forKey: .currency)
        case let .unknown(t):
            // Only the type discriminator round-trips; unknown fields are not preserved
            try container.encode(MetricKind.unknown(t), forKey: .type)
        }
    }
}

