/// A single JSONL row in the usage-history file. One row per metric per tick.
///
/// Shape is deliberately flat and disjoint from `UsagesFile` so consumers of the
/// history format can reason about it in isolation — it is not a projection of
/// the usages.json schema.
public struct SnapshotEntry: Codable, Equatable, Sendable {
    public let timestamp: ISODate
    public let vendor: Vendor
    public let account: AccountEmail
    public let metricName: String
    public let kind: MetricKind
    public let usagePercent: UsagePercent?
    public let currentAmount: Double?
    public let currency: String?

    public init(
        timestamp: ISODate,
        vendor: Vendor,
        account: AccountEmail,
        metricName: String,
        kind: MetricKind,
        usagePercent: UsagePercent? = nil,
        currentAmount: Double? = nil,
        currency: String? = nil
    ) {
        self.timestamp = timestamp
        self.vendor = vendor
        self.account = account
        self.metricName = metricName
        self.kind = kind
        self.usagePercent = usagePercent
        self.currentAmount = currentAmount
        self.currency = currency
    }

    private enum CodingKeys: String, CodingKey {
        case timestamp, vendor, account, metricName, kind
        case usagePercent, currentAmount, currency
    }

    public init(from decoder: Decoder) throws {
        let container = try decoder.container(keyedBy: CodingKeys.self)
        timestamp = try container.decode(ISODate.self, forKey: .timestamp)
        vendor = try container.decode(Vendor.self, forKey: .vendor)
        account = try container.decode(AccountEmail.self, forKey: .account)
        metricName = try container.decode(String.self, forKey: .metricName)
        kind = try container.decode(MetricKind.self, forKey: .kind)
        usagePercent = try container.decodeIfPresent(UsagePercent.self, forKey: .usagePercent)
        currentAmount = try container.decodeIfPresent(Double.self, forKey: .currentAmount)
        currency = try container.decodeIfPresent(String.self, forKey: .currency)
    }

    public func encode(to encoder: Encoder) throws {
        var container = encoder.container(keyedBy: CodingKeys.self)
        try container.encode(timestamp, forKey: .timestamp)
        try container.encode(vendor, forKey: .vendor)
        try container.encode(account, forKey: .account)
        try container.encode(metricName, forKey: .metricName)
        try container.encode(kind, forKey: .kind)
        try container.encodeIfPresent(usagePercent, forKey: .usagePercent)
        try container.encodeIfPresent(currentAmount, forKey: .currentAmount)
        try container.encodeIfPresent(currency, forKey: .currency)
    }
}

