        }

        let targetURL: URL
        do {
            targetURL = try prepareDailyFile(for: now)
        } catch {
            logger.log(.error, "SnapshotRecorder: failed to prepare daily file: \(error)")
            return
        }

        do {
            try append(entries: entries, to: targetURL)
        } catch {
            logger.log(.error, "SnapshotRecorder: append failed at \(targetURL.path): \(error)")
            return
        }

        lastWrittenSignature = signature
        logger.log(.info, "SnapshotRecorder: appended \(entries.count) line(s) to \(targetURL.path)")
    }

    // MARK: - Helpers

    static func flatten(usages: [VendorUsageEntry], timestamp: ISODate) -> [SnapshotEntry] {
        var out: [SnapshotEntry] = []
        for entry in usages {
            for metric in entry.metrics {
                switch metric {
                case let .timeWindow(name, _, _, usagePercent):
                    out.append(SnapshotEntry(
                        timestamp: timestamp,
                        vendor: entry.vendor,
                        account: entry.account,
                        metricName: name,
                        kind: .timeWindow,
                        usagePercent: usagePercent
                    ))
                case let .payAsYouGo(name, amount, currency):
                    out.append(SnapshotEntry(
                        timestamp: timestamp,
                        vendor: entry.vendor,
                        account: entry.account,
                        metricName: name,
                        kind: .payAsYouGo,
                        currentAmount: amount,
                        currency: currency
                    ))
                case .unknown:
                    // Forward-compatibility placeholder — no payload to record.
                    continue
                }
            }
        }
        return out
    }

    static func makeSignature(_ entries: [SnapshotEntry]) -> [String] {
        entries.map { entry in
            let kindKey: String
            switch entry.kind {
            case .timeWindow:           kindKey = "tw"
            case .payAsYouGo:           kindKey = "payg"
            case .unknown(let raw):     kindKey = "u:\(raw)"
            }
            let percent = entry.usagePercent.map { String($0.rawValue) } ?? "-"
            let amount = entry.currentAmount.map { String($0) } ?? "-"
            let currency = entry.currency ?? "-"
            return [
                entry.vendor.rawValue,
                entry.account.rawValue,
                entry.metricName,
                kindKey,
                percent,
                amount,
                currency,
            ].joined(separator: "|")
        }.sorted()
    }

    private func prepareDailyFile(for date: Date) throws -> URL {
        let components = calendar.dateComponents([.year, .month, .day], from: date)
        let year = String(format: "%04d", components.year ?? 0)
        let month = String(format: "%02d", components.month ?? 0)
        let day = String(format: "%02d", components.day ?? 0)
        let dir = URL(fileURLWithPath: rootPath)
            .appendingPathComponent(year, isDirectory: true)
            .appendingPathComponent(month, isDirectory: true)
        try fileManager.createDirectory(at: dir, withIntermediateDirectories: true)
        return dir.appendingPathComponent("\(year)-\(month)-\(day).jsonl")
    }

    private func append(entries: [SnapshotEntry], to url: URL) throws {
        let encoder = JSONEncoder()
        encoder.outputFormatting = [.sortedKeys]
        var payload = Data()
        for entry in entries {
            payload.append(try encoder.encode(entry))
            payload.append(Self.newlineByte)
        }

        if !fileManager.fileExists(atPath: url.path) {
            // createFile returns false if the path is unwritable; surface that as an error
            // instead of letting the subsequent FileHandle open throw a more cryptic one.
            guard fileManager.createFile(atPath: url.path, contents: nil) else {
                throw SnapshotRecorderError.cannotCreateFile(path: url.path)
            }
        }

        let handle = try FileHandle(forWritingTo: url)
        defer { try? handle.close() }
        try handle.seekToEnd()
        try handle.write(contentsOf: payload)
    }

    private static let newlineByte: UInt8 = 0x0A
}

public enum SnapshotRecorderError: Error, CustomStringConvertible {
    case cannotCreateFile(path: String)

    public var description: String {
        switch self {
        case let .cannotCreateFile(path): "Cannot create snapshot file at \(path)"
        }
    }
}

